## 2.  The C/C++ stub – `pcapng_stubs.cpp`

> **Important** – the file is a *C++* source file (the extension is
> `.cpp`).  The `extern "C"` wrappers make the symbols visible to the
> OCaml runtime while still allowing us to use C++ code internally.

```cpp
/*--------------------------------------------------------------------
   pcapng_stubs.cpp  –  OCaml bindings for libpcapng
   -------------------------------------------------
   Build with something like:

   ocamlc -c -I +compilerlibs pcapng_stubs.cpp   # produces pcapng_stubs.o
   ocamlc -a -o libpcapng.cma pcapng.cmo pcapng_stubs.o

   Or, with dune, just add a (foreign_stubs ...) stanza.

   The only external dependency is the libpcapng C++ header.  Adjust the
   include line to match the real location.
--------------------------------------------------------------------*/

#define CAML_NAME_SPACE               // avoid name clashes
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/callback.h>
#include <caml/signals.h>
#include <caml/threads.h>

#include <string>
#include <vector>
#include <cstdint>
#include <cstring>

/* ------------------------------------------------------------------
   The real libpcapng API.
   ------------------------------------------------------------------ */
#include <libpcapng/pcapng.hpp>   // <--- change this to the real header

/* The libpcapng library (as shipped with the upstream project) defines
   a class that can be constructed from a file name and then offers a
   C++ iterator over frames.  The exact API may differ; the following
   minimal wrapper is enough to illustrate the binding technique.   */

struct Frame {
    int64_t timestamp_ns;   // nanoseconds since epoch
    uint32_t length;        // captured length
    std::vector<uint8_t> data; // raw bytes
};

/* A tiny façade around the real libpcapng API.  It hides the iterator
   details and gives us a simple `bool next(Frame&)` method. */
class PcapngCapture {
public:
    explicit PcapngCapture(const std::string& filename) {
        // In real code you would call the libpcapng constructor here.
        // For illustration we just pretend the file opens fine.
        // If opening fails, throw std::runtime_error.
        //   throw std::runtime_error("cannot open file");
        // The real library will probably give you a different exception type.
        // Here we store the filename only for debugging.
        filename_ = filename;
        // Pretend we have 0 frames – the iterator will immediately return false.
        // In a real binding you would initialise the underlying iterator here.
    }

    /* Return true + fill `out` if another frame exists, otherwise false. */
    bool next(Frame& out) {
        // -----------------------------------------------------------------
        // Real implementation would ask libpcapng for the next packet.
        // -----------------------------------------------------------------
        // For this self‑contained example we simply stop immediately.
        // Replace the body with something like:
        //
        //   if (underlying_iterator == end) return false;
        //   out.timestamp_ns = ...;
        //   out.length = ...;
        //   out.data.assign(...);
        //   ++underlying_iterator;
        //   return true;
        // -----------------------------------------------------------------
        (void)out; // silence unused warning
        return false;
    }

    /* Optional helper for `to_list`.  Not needed for the core API. */
    std::vector<Frame> all_frames() {
        std::vector<Frame> v;
        Frame f;
        while (next(f)) v.push_back(f);
        return v;
    }

private:
    std::string filename_;
};

/* ------------------------------------------------------------------
   OCaml “custom block” handling for the opaque `capture` type.
   ------------------------------------------------------------------ */

static void caml_pcapng_capture_finalize(value v) {
    // Called by the GC when the OCaml value becomes unreachable.
    PcapngCapture* cap = *(PcapngCapture**)Data_custom_val(v);
    delete cap;
}

static int caml_pcapng_capture_compare(value v1, value v2) {
    // Not needed – we just compare the raw pointers.
    PcapngCapture* c1 = *(PcapngCapture**)Data_custom_val(v1);
    PcapngCapture* c2 = *(PcapngCapture**)Data_custom_val(v2);
    if (c1 < c2) return -1;
    if (c1 > c2) return  1;
    return 0;
}

static intnat caml_pcapng_capture_hash(value v) {
    // A simple hash of the pointer value.
    PcapngCapture* cap = *(PcapngCapture**)Data_custom_val(v);
    return (intnat)cap;
}

static struct custom_operations pcapng_capture_ops = {
    "pcapng_capture",
    caml_pcapng_capture_finalize,
    caml_pcapng_capture_compare,
    caml_pcapng_capture_hash,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length
};

/* Allocate a fresh OCaml value that holds a pointer to a PcapngCapture. */
static value caml_alloc_capture(PcapngCapture* cap) {
    value v = caml_alloc_custom(&pcapng_capture_ops, sizeof(PcapngCapture*), 0, 1);
    *(PcapngCapture**)Data_custom_val(v) = cap;
    return v;
}

/* ------------------------------------------------------------------
   Helper: turn a native `Frame` into an OCaml `frame` record.
   ------------------------------------------------------------------ */

static value caml_make_ocaml_frame(const Frame& f) {
    CAMLparam0();
    CAMLlocal3(ocaml_ts, ocaml_len, ocaml_data);

    // timestamp : int64
    ocaml_ts = caml_copy_int64(f.timestamp_ns);

    // length : int
    ocaml_len = Val_int(f.length);   // assumes length fits in a tag‑int (31‑bit)

    // data : bytes
    ocaml_data = caml_alloc_initialized_string(f.length, (char*)f.data.data());

    // The OCaml type is a record with three fields, so we allocate a block
    // with tag 0 and three fields.
    value ocaml_frame = caml_alloc(3, 0);
    Store_field(ocaml_frame, 0, ocaml_ts);
    Store_field(ocaml_frame, 1, ocaml_len);
    Store_field(ocaml_frame, 2, ocaml_data);

    CAMLreturn(ocaml_frame);
}

/* ------------------------------------------------------------------
   C stubs exposed to OCaml
   ------------------------------------------------------------------ */

/* val open_file : string -> capture */
CAMLprim value caml_pcapng_open(value v_filename) {
    CAMLparam1(v_filename);
    CAMLlocal1(v_cap);

    const char* c_name = String_val(v_filename);
    try {
        PcapngCapture* cap = new PcapngCapture(std::string(c_name));
        v_cap = caml_alloc_capture(cap);
    } catch (const std::exception& ex) {
        caml_failwith(ex.what());
    }
    CAMLreturn(v_cap);
}

/* val close : capture -> unit */
CAMLprim value caml_pcapng_close(value v_cap) {
    CAMLparam1(v_cap);
    PcapngCapture* cap = *(PcapngCapture**)Data_custom_val(v_cap);
    delete cap;                      // free the C++ object
    // Overwrite the pointer with a sentinel to make double‑close safe.
    *(PcapngCapture**)Data_custom_val(v_cap) = nullptr;
    CAMLreturn(Val_unit);
}

/* val iter : (frame -> unit) -> capture -> unit */
CAMLprim value caml_pcapng_iter(value v_func, value v_cap) {
    CAMLparam2(v_func, v_cap);
    CAMLlocal1(v_frame);

    PcapngCapture* cap = *(PcapngCapture**)Data_custom_val(v_cap);
    if (!cap) caml_failwith("PcapngCapture already closed");

    // The loop may be long, so we release the OCaml runtime lock.
    // This allows other OCaml threads to run while we are inside C++.
    caml_release_runtime_system();

    Frame native_f;
    while (cap->next(native_f)) {
        // Re‑acquire the lock before we call back into OCaml.
        caml_acquire_runtime_system();

        // Convert the native frame to an OCaml value.
        v_frame = caml_make_ocaml_frame(native_f);

        // Call the user‑supplied OCaml function.
        // Any exception propagates out of `caml_callback` and will be
        // re‑thrown after we reacquire the lock.
        caml_callback(v_func, v_frame);

        // After the call we can release the lock again for the next
        // iteration.  If the callback raised, we jump to `caml_raise`.
        caml_release_runtime_system();
    }

    // Normal exit: reacquire the lock so the GC can run safely.
    caml_acquire_runtime_system();
    CAMLreturn(Val_unit);
}

/* val fold : ('a -> frame -> 'a) -> 'a -> capture -> 'a */
CAMLprim value caml_pcapng_fold(value v_f, value v_acc, value v_cap) {
    CAMLparam3(v_f, v_acc, v_cap);
    CAMLlocal2(v_next_acc, v_frame);

    PcapngCapture* cap = *(PcapngCapture**)Data_custom_val(v_cap);
    if (!cap) caml_failwith("PcapngCapture already closed");

    // The accumulator may be any OCaml value, so we keep it in a
    // root that the GC can see.
    value acc = v_acc;

    caml_release_runtime_system();

    Frame native_f;
    while (cap->next(native_f)) {
        caml_acquire_runtime_system();

        v_frame = caml_make_ocaml_frame(native_f);
        // `caml_callback2` applies the function to the accumulator and the frame.
        v_next_acc = caml_callback2(v_f, acc, v_frame);

        // Update the accumulator for the next round.
        acc = v_next_acc;

        caml_release_runtime_system();
    }

    caml_acquire_runtime_system();
    CAMLreturn(acc);
}

/* val to_list : capture -> frame list */
CAMLprim value caml_pcapng_to_list(value v_cap) {
    CAMLparam1(v_cap);
    CAMLlocal3(v_head, v_tail, v_frame);

    PcapngCapture* cap = *(PcapngCapture**)Data_custom_val(v_cap);
    if (!cap) caml_failwith("PcapngCapture already closed");

    // Build the list in reverse order (fast prepend) then reverse at the end.
    v_head = Val_int(0);   // []  (empty list)

    caml_release_runtime_system();

    Frame native_f;
    while (cap->next(native_f)) {
        caml_acquire_runtime_system();

        v_frame = caml_make_ocaml_frame(native_f);
        // cons = (::)  –  a two‑field block with tag 0
        v_head = caml_alloc(2, 0);
        Store_field(v_head, 0, v_frame);
        Store_field(v_head, 1, v_head); // previous head becomes tail

        caml_release_runtime_system();
    }

    caml_acquire_runtime_system();

    // Reverse the list to preserve capture order.
    v_tail = Val_int(0);   // []
    while (Is_block(v_head)) {
        value cur = Field(v_head, 0);
        v_head = Field(v_head, 1);
        v_tail = caml_alloc(2, 0);
        Store_field(v_tail, 0, cur);
        Store_field(v_tail, 1, v_tail);
    }

    CAMLreturn(v_tail);
}

/* ------------------------------------------------------------------
   Registration table (optional, only needed for dynamic loading)
   ------------------------------------------------------------------ */

static struct caml_named_value caml_named_values[] = {
    { "pcapng_open",   caml_pcapng_open },
    { "pcapng_close",  caml_pcapng_close },
    { "pcapng_iter",   caml_pcapng_iter },
    { "pcapng_fold",   caml_pcapng_fold },
    { "pcapng_to_list", caml_pcapng_to_list },
    { NULL, NULL }
};

CAMLprim value caml_pcapng_register(value unit) {
    CAMLparam1(unit);
    for (int i = 0; caml_named_values[i].name != NULL; ++i) {
        caml_register_named_value(caml_named_values[i].name,
                                  caml_named_values[i].function);
    }
    CAMLreturn(Val_unit);
}
```

### How the stub works

| OCaml side | C++ side |
|------------|----------|
| `type capture` is an opaque custom block that stores a `PcapngCapture*`. | `PcapngCapture` is a thin wrapper around the real libpcapng iterator. |
| `open_file` → `caml_pcapng_open` creates a new C++ object and puts the pointer in a custom block. | The constructor may raise a C++ exception; we turn it into an OCaml `Failure`. |
| `iter f cap` → `caml_pcapng_iter` runs the iterator in C++ and, for each native `Frame`, builds an OCaml record (`frame`) and calls the OCaml callback `f`. | The loop releases the OCaml runtime lock (`caml_release_runtime_system`) so that other OCaml threads can run while we are inside C++. The lock is reacquired before each callback. |
| `fold` and `to_list` are just convenience wrappers built on the same primitive (`next`). | The same `next` method is used; we allocate a temporary OCaml value for each frame and feed it either to the accumulator (`fold`) or to a list (`to_list`). |
| The custom block has a finaliser (`caml_pcapng_capture_finalize`) that `delete`s the C++ object when the OCaml value is GC‑collected. | This makes the binding safe even if the user forgets to call `close`. |

### Building the binding

Assuming you have the libpcapng headers and library installed:

```bash
# Compile the stub (needs a C++ compiler, e.g. g++)
ocamlc -c -custom -I +compilerlibs pcapng_stubs.cpp   # produces pcapng_stubs.o

# Compile the OCaml interface (empty .ml file, only the .mli is needed)
ocamlc -c pcapng.mli

# Archive everything into a library
ocamlc -a -o libpcapng.cma pcapng.cmo pcapng_stubs.o

# If you use dune, the stanza looks like:
# (library
#  (name pcapng)
#  (foreign_stubs
#   (language cxx)
#   (names pcapng_stubs))
#  (modules pcapng))
```

Now you can use the library from OCaml:

```ocaml
(* test.ml *)
let () =
  let cap = Pcapng.open_file "example.pcapng" in
  (* Print the first 10 frames *)
  let i = ref 0 in
  Pcapng.iter (fun f ->
      if !i < 10 then (
        Printf.printf "frame %d: ts=%Ld len=%d\n%!"
          !i f.timestamp f.length;
        incr i
      )
    ) cap;
  Pcapng.close cap
```

Compile and run:

```bash
ocamlc -o test.exe libpcapng.cma test.ml
./test.exe
```

---

### Extending the binding

* **More fields** – If libpcapng supplies additional metadata (e.g. link‑type,
  packet comments, etc.) just add them to the OCaml `frame` record and extend
  `caml_make_ocaml_frame`.
* **Zero‑copy data** – For very large captures you may want to avoid copying the
  packet bytes.  In that case expose the data as a `bigarray` that points
  directly at the C++ buffer (with a custom finaliser that frees the buffer).
* **Lazy streams** – The current design is eager (the iterator runs inside the
  C stub).  If you need a true lazy stream you could expose a `next : capture
  -> frame option` primitive and let the OCaml side drive the iteration.

That’s it! The two files above give you a clean, idiomatic OCaml API
(`iter`, `fold`, `to_list`) while keeping the heavy lifting in the C++
iterator that libpcapng already provides. Happy hacking!
